import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { NavbarComponent } from '../../components/navbar/navbar.component';
import { Movie, MovieService } from '../../services/movie.service';
import { WatchlistService } from '../../services/watchlist.service';

@Component({
  selector: 'app-movies',
  standalone: true,
  imports: [CommonModule, FormsModule, NavbarComponent],
  templateUrl: './movies.component.html',
  styleUrl: './movies.component.css'
})
export class MoviesComponent implements OnInit {
  movies: Movie[] = [];
  watchlistIds = new Set<number>();
  loading = true;
  error: string | null = null;
  searchTerm = '';

  constructor(
    private movieService: MovieService,
    private watchlistService: WatchlistService,
    private router: Router
  ) {}

  ngOnInit() {
    this.loadData();
  }

  loadData() {
    this.loading = true;

    this.movieService.getMovies().subscribe({
      next: (movies) => {
        this.movies = movies;
        this.loadWatchlistStatus();
      },
      error: () => {
        this.error = 'Failed to load movies';
        this.loading = false;
      }
    });
  }

  loadWatchlistStatus() {
    this.watchlistService.getWatchlist().subscribe({
      next: (items) => {
        this.watchlistIds = new Set(items.map(i => i.movieId));
        this.loading = false;
      },
      error: () => {
        this.loading = false;
      }
    });
  }

  get filteredMovies(): Movie[] {
    if (!this.searchTerm.trim()) return this.movies;
    const term = this.searchTerm.toLowerCase();
    return this.movies.filter(m =>
      m.title.toLowerCase().includes(term) ||
      (m.categoryName?.toLowerCase().includes(term))
    );
  }

  isInWatchlist(movieId: number): boolean {
    return this.watchlistIds.has(movieId);
  }

  toggleWatchlist(movieId: number) {
    if (this.isInWatchlist(movieId)) {
      this.watchlistService.removeFromWatchlist(movieId).subscribe({
        next: () => this.watchlistIds.delete(movieId),
        error: () => this.error = 'Failed to remove from watchlist'
      });
    } else {
      this.watchlistService.addToWatchlist(movieId).subscribe({
        next: () => this.watchlistIds.add(movieId),
        error: (err) => this.error = err.error?.message || 'Failed to add to watchlist'
      });
    }
  }

  writeReview(movieId: number) {
    this.router.navigate(['/create-review'], { queryParams: { movieId } });
  }
}
<div class="page-container">
  <app-navbar></app-navbar>

  <div class="page-content">
    <h1>Browse Movies</h1>

    <input
      type="text"
      class="search-input"
      placeholder="Search by title or category..."
      [(ngModel)]="searchTerm"
    />

    <div *ngIf="loading" class="loading">Loading movies...</div>
    <div *ngIf="error" class="error-message">{{ error }}</div>

    <div *ngIf="!loading && filteredMovies.length === 0" class="empty-state">
      No movies found.
    </div>

    <div *ngIf="!loading && filteredMovies.length > 0" class="movie-grid">
      <div *ngFor="let movie of filteredMovies" class="movie-card">
        <img *ngIf="movie.imagePath" [src]="movie.imagePath" [alt]="movie.title" class="movie-poster" />
        <div *ngIf="!movie.imagePath" class="movie-poster placeholder">🎬</div>
        <div class="movie-info">
          <h3>{{ movie.title }}</h3>
          <span class="category" *ngIf="movie.categoryName">{{ movie.categoryName }}</span>
          <p class="description">{{ movie.description | slice:0:100 }}{{ movie.description.length > 100 ? '...' : '' }}</p>
          <div class="rating-info" *ngIf="movie.reviewCount > 0">
            ⭐ {{ movie.averageRating | number:'1.1-1' }} ({{ movie.reviewCount }} reviews)
          </div>
          <div class="card-actions">
            <button
              class="btn"
              [class.btn-success]="isInWatchlist(movie.id)"
              [class.btn-outline]="!isInWatchlist(movie.id)"
              (click)="toggleWatchlist(movie.id)"
            >
              {{ isInWatchlist(movie.id) ? '✓ In Watchlist' : '+ Add to Watchlist' }}
            </button>
            <button class="btn btn-primary btn-sm" (click)="writeReview(movie.id)">Review</button>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>
